--
-- Name: fn_audit_checksum(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_audit_checksum() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.checksum = encode(
        sha256(
            convert_to(
                COALESCE(NEW.tenant_id::text, '') || '|' ||
                COALESCE(NEW.actor_id::text, '') || '|' ||
                COALESCE(NEW.action, '') || '|' ||
                COALESCE(NEW.entity_type, '') || '|' ||
                COALESCE(NEW.entity_id::text, '') || '|' ||
                COALESCE(NEW.changes::text, '') || '|' ||
                COALESCE(NEW.timestamp::text, ''),
                'UTF8'
            )
        ),
        'hex'
    );
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_audit_checksum() OWNER TO opms;

--
-- Name: fn_catalog_item_search_vector(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_catalog_item_search_vector() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.search_vector :=
        setweight(to_tsvector('english', COALESCE(NEW.name, '')), 'A') ||
        setweight(to_tsvector('english', COALESCE(NEW.description, '')), 'B');
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_catalog_item_search_vector() OWNER TO opms;

--
-- Name: fn_generate_problem_number(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_generate_problem_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.problem_number IS NULL OR NEW.problem_number = '' THEN
        NEW.problem_number := 'PRB-' || LPAD(nextval('problem_seq')::text, 6, '0');
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_generate_problem_number() OWNER TO opms;

--
-- Name: fn_generate_request_number(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_generate_request_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.request_number IS NULL OR NEW.request_number = '' THEN
        NEW.request_number := 'REQ-' || LPAD(nextval('service_request_seq')::text, 6, '0');
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_generate_request_number() OWNER TO opms;

--
-- Name: fn_generate_ticket_number(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_generate_ticket_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.ticket_number IS NULL OR NEW.ticket_number = '' THEN
        CASE NEW.type
            WHEN 'incident' THEN
                NEW.ticket_number := 'INC-' || LPAD(nextval('ticket_seq')::text, 6, '0');
            WHEN 'service_request' THEN
                NEW.ticket_number := 'SR-' || LPAD(nextval('ticket_seq')::text, 6, '0');
            WHEN 'change' THEN
                NEW.ticket_number := 'CHG-' || LPAD(nextval('ticket_seq')::text, 6, '0');
            ELSE
                NEW.ticket_number := 'TKT-' || LPAD(nextval('ticket_seq')::text, 6, '0');
        END CASE;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_generate_ticket_number() OWNER TO opms;

--
-- Name: fn_org_hierarchy_insert(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_org_hierarchy_insert() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Self-reference (depth 0)
    INSERT INTO org_hierarchy (ancestor_id, descendant_id, depth)
    VALUES (NEW.id, NEW.id, 0);

    -- Copy ancestor paths from parent
    IF NEW.parent_id IS NOT NULL THEN
        INSERT INTO org_hierarchy (ancestor_id, descendant_id, depth)
        SELECT h.ancestor_id, NEW.id, h.depth + 1
        FROM org_hierarchy h
        WHERE h.descendant_id = NEW.parent_id;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_org_hierarchy_insert() OWNER TO opms;

--
-- Name: fn_resolve_visible_org_units(uuid, uuid); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_resolve_visible_org_units(p_user_id uuid, p_tenant_id uuid) RETURNS TABLE(org_unit_id uuid)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    -- Global bypass: users with global_admin, auditor, or itd_director roles,
    -- or any role binding with scope_type = 'global', see all org units.
    IF EXISTS (
        SELECT 1 FROM role_bindings rb
        JOIN roles r ON r.id = rb.role_id
        WHERE rb.user_id = p_user_id
          AND rb.is_active = true
          AND (rb.expires_at IS NULL OR rb.expires_at > NOW())
          AND (r.name IN ('global_admin', 'auditor', 'itd_director')
               OR rb.scope_type = 'global')
    ) THEN
        RETURN QUERY
        SELECT o.id FROM org_units o
        WHERE o.tenant_id = p_tenant_id AND o.is_active = true;
        RETURN;
    END IF;

    -- Scoped roles: for each role binding, use the closure table to resolve
    -- all descendants of the scope anchor (scope_id or user's org_unit).
    RETURN QUERY
    SELECT DISTINCT sub.oid FROM (
        -- From direct role bindings: resolve descendants of scope anchor
        SELECT h.descendant_id AS oid
        FROM role_bindings rb
        JOIN org_hierarchy h ON h.ancestor_id = COALESCE(
            rb.scope_id,
            (SELECT u.org_unit_id FROM users u WHERE u.id = p_user_id)
        )
        WHERE rb.user_id = p_user_id
          AND rb.is_active = true
          AND (rb.expires_at IS NULL OR rb.expires_at > NOW())
          AND COALESCE(
              rb.scope_id,
              (SELECT u.org_unit_id FROM users u WHERE u.id = p_user_id)
          ) IS NOT NULL

        UNION

        -- Always include the user's own org unit (self-scope)
        SELECT u.org_unit_id AS oid
        FROM users u
        WHERE u.id = p_user_id
          AND u.org_unit_id IS NOT NULL

        UNION

        -- Active delegations: inherit the delegator's org scope
        SELECT h.descendant_id AS oid
        FROM delegations d
        JOIN users delegator ON delegator.id = d.delegator_id
        JOIN org_hierarchy h ON h.ancestor_id = delegator.org_unit_id
        WHERE d.delegate_id = p_user_id
          AND d.is_active = true
          AND d.starts_at <= NOW()
          AND d.ends_at > NOW()
          AND delegator.org_unit_id IS NOT NULL
    ) sub;
END;
$$;


ALTER FUNCTION public.fn_resolve_visible_org_units(p_user_id uuid, p_tenant_id uuid) OWNER TO opms;

--
-- Name: fn_update_project_budget_spent(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_update_project_budget_spent() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE projects SET budget_spent = (
        SELECT COALESCE(SUM(amount), 0) FROM project_cost_entries
        WHERE project_id = COALESCE(NEW.project_id, OLD.project_id) AND entry_type = 'actual'
    ), updated_at = NOW()
    WHERE id = COALESCE(NEW.project_id, OLD.project_id);
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_update_project_budget_spent() OWNER TO opms;

--
-- Name: fn_update_timestamp(); Type: FUNCTION; Schema: public; Owner: opms
--

CREATE FUNCTION public.fn_update_timestamp() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_update_timestamp() OWNER TO opms;

