-- Name: mv_catalog_item_popularity; Type: MATERIALIZED VIEW; Schema: public; Owner: opms
--

CREATE MATERIALIZED VIEW public.mv_catalog_item_popularity AS
 SELECT ci.tenant_id,
    ci.id AS item_id,
    ci.name AS item_name,
    count(sr.id) AS request_count,
    max(sr.created_at) AS last_requested_at
   FROM (public.service_catalog_items ci
     LEFT JOIN public.service_requests sr ON ((sr.catalog_item_id = ci.id)))
  WHERE (ci.status = 'active'::text)
  GROUP BY ci.tenant_id, ci.id, ci.name
  WITH NO DATA;


