-- Name: risks; Type: TABLE; Schema: public; Owner: opms
--

CREATE TABLE public.risks (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid NOT NULL,
    risk_number text NOT NULL,
    title text NOT NULL,
    description text,
    category text DEFAULT 'operational'::text NOT NULL,
    likelihood text DEFAULT 'medium'::text NOT NULL,
    impact text DEFAULT 'medium'::text NOT NULL,
    risk_score integer GENERATED ALWAYS AS ((
CASE likelihood
    WHEN 'very_low'::text THEN 1
    WHEN 'low'::text THEN 2
    WHEN 'medium'::text THEN 3
    WHEN 'high'::text THEN 4
    WHEN 'very_high'::text THEN 5
    ELSE NULL::integer
END *
CASE impact
    WHEN 'very_low'::text THEN 1
    WHEN 'low'::text THEN 2
    WHEN 'medium'::text THEN 3
    WHEN 'high'::text THEN 4
    WHEN 'very_high'::text THEN 5
    ELSE NULL::integer
END)) STORED,
    status text DEFAULT 'identified'::text NOT NULL,
    treatment_plan text,
    contingency_plan text,
    owner_id uuid,
    reviewer_id uuid,
    review_date date,
    next_review_date date,
    linked_project_id uuid,
    linked_audit_id uuid,
    escalation_threshold integer DEFAULT 15,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    org_unit_id uuid,
    CONSTRAINT risks_impact_check CHECK ((impact = ANY (ARRAY['very_low'::text, 'low'::text, 'medium'::text, 'high'::text, 'very_high'::text]))),
    CONSTRAINT risks_likelihood_check CHECK ((likelihood = ANY (ARRAY['very_low'::text, 'low'::text, 'medium'::text, 'high'::text, 'very_high'::text]))),
    CONSTRAINT risks_status_check CHECK ((status = ANY (ARRAY['identified'::text, 'assessed'::text, 'mitigating'::text, 'accepted'::text, 'closed'::text, 'escalated'::text])))
);

