--
-- Name: risk_register; Type: TABLE; Schema: public; Owner: opms
--

CREATE TABLE public.risk_register (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid NOT NULL,
    project_id uuid,
    title text NOT NULL,
    description text,
    category text,
    likelihood text DEFAULT 'medium'::text NOT NULL,
    impact text DEFAULT 'medium'::text NOT NULL,
    risk_score integer GENERATED ALWAYS AS ((
CASE likelihood
    WHEN 'very_low'::text THEN 1
    WHEN 'low'::text THEN 2
    WHEN 'medium'::text THEN 3
    WHEN 'high'::text THEN 4
    WHEN 'very_high'::text THEN 5
    ELSE 3
END *
CASE impact
    WHEN 'very_low'::text THEN 1
    WHEN 'low'::text THEN 2
    WHEN 'medium'::text THEN 3
    WHEN 'high'::text THEN 4
    WHEN 'very_high'::text THEN 5
    ELSE 3
END)) STORED,
    status text DEFAULT 'identified'::text NOT NULL,
    mitigation_plan text,
    contingency_plan text,
    owner_id uuid,
    review_date date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);

